const body = $input.first().json;
const event = body.event || body.type || '';
const data  = body.data  || body;

if (event !== 'messages.upsert' && event !== 'message') {
  return [{ json: { skip: true, reason: `Ignored event: ${event}` } }];
}

const message = data.message || {};
const key     = data.key     || {};

if (key.fromMe) {
  return [{ json: { skip: true, reason: 'Own message.' } }];
}

const remoteJid = key.remoteJid || '';
const phone     = remoteJid.replace(/@(s\.whatsapp\.net|lid|c\.us)$/, '');
const text      = (
  message.conversation ||
  message.extendedTextMessage?.text ||
  ''
).trim();

if (!text) {
  return [{ json: { skip: true, reason: 'No text content.' } }];
}

// Extract name — look for patterns like "Meu nome é João" or just use pushName
const pushName = data.pushName || '';
const nameMatch = text.match(/(?:meu nome [eé]|me chamo|sou o?a?)\s+([A-ZÀ-Ü][a-zà-ü]+(\s[A-ZÀ-Ü][a-zà-ü]+)*)/i);
const name = nameMatch ? nameMatch[1].trim() : (pushName || 'Desconhecido');

// Format phone to E.164 (Brazil default +55)
const digitsOnly = phone.replace(/\D/g, '');
const e164 = digitsOnly.startsWith('55') ? `+${digitsOnly}` : `+55${digitsOnly}`;

return [{
  json: {
    skip: false,
    instanceName: body.instance || data.instanceName || 'default',
    name,
    phone: e164,
    phoneRaw: phone,
    remoteJid,
    messageText: text,
    capturedAt: new Date().toISOString(),
    source: 'whatsapp'
  }
}];
